// Generated by AI Assistant

import { RootState } from '@/store';
import { AiConfigState, unloadedState } from '@/plugins/ai-selector/store/AiConfig/reducer';
import {
  selectAiConfigEnabled,
  selectAiConfigError,
  selectAiConfigIsLoading,
  selectAiProviderKeyExists,
  selectAiProviders,
  selectAiTools,
  selectDefaultAiProviders,
} from '@/plugins/ai-selector/store/AiConfig/selectors';

function buildState(overrides: Partial<AiConfigState> = {}): RootState {
  return {
    aiConfig: { ...unloadedState, ...overrides },
  } as RootState;
}

describe('AiConfig, selectors', () => {
  it('should select providers', () => {
    const providers = [{ id: 'p1', name: 'Provider 1' }];
    const state = buildState({
      providers: providers as AiConfigState['providers'],
    });
    expect(selectAiProviders(state)).toBe(providers);
  });

  it('should select tools', () => {
    const tools = [{ providerId: 't1', name: 'Tool 1' }];
    const state = buildState({
      tools: tools as AiConfigState['tools'],
    });
    expect(selectAiTools(state)).toBe(tools);
  });

  it('should select default AI providers', () => {
    const defaults = ['openai', 'anthropic'];
    const state = buildState({ defaultAiProviders: defaults });
    expect(selectDefaultAiProviders(state)).toBe(defaults);
  });

  it('should return true when providers and tools are non-empty', () => {
    const state = buildState({
      providers: [{ id: 'p1' }] as AiConfigState['providers'],
      tools: [{ providerId: 't1' }] as AiConfigState['tools'],
    });
    expect(selectAiConfigEnabled(state)).toBe(true);
  });

  it('should return false when providers are empty', () => {
    const state = buildState({
      providers: [],
      tools: [{ providerId: 't1' }] as AiConfigState['tools'],
    });
    expect(selectAiConfigEnabled(state)).toBe(false);
  });

  it('should return false when tools are empty', () => {
    const state = buildState({
      providers: [{ id: 'p1' }] as AiConfigState['providers'],
      tools: [],
    });
    expect(selectAiConfigEnabled(state)).toBe(false);
  });

  it('should select provider key existence map', () => {
    const keyMap = { anthropic: true, openai: false };
    const state = buildState({ providerKeyExists: keyMap });
    expect(selectAiProviderKeyExists(state)).toBe(keyMap);
  });

  it('should select loading state', () => {
    const state = buildState({ isLoading: true });
    expect(selectAiConfigIsLoading(state)).toBe(true);
  });

  it('should select error', () => {
    const state = buildState({ error: 'something failed' });
    expect(selectAiConfigError(state)).toBe('something failed');
  });

  it('should return undefined error from initial state', () => {
    const state = buildState();
    expect(selectAiConfigError(state)).toBeUndefined();
  });
});
